checker_dsl:
EXISTS (`Cookie instance CI`, `Expression input`, `Expression store`, `SensitiveSource data`) {
  AND {
    (`CI is a constructor call for class javax.servlet.http.Cookie or jakarta.servlet.http.Cookie`),
    (`input is the second argument (index 1) of CI`),
    (`data flows to input`),
    EXISTS (`MethodCall MC`, `Method M`) {
      AND {
        (`MC calls method M`),
        (`M has name "addCookie"`),
        (`M is declared in type javax.servlet.http.HttpServletResponse or jakarta.servlet.http.HttpServletResponse`),
        (`store = MC`),
        (`CI equals one argument of MC`),
        (`there is data flow from CI to the DataFlow node representing that argument of MC`)
      }
    }
  }
}
